let datos = msg.payload.datos_sensores;
if (!datos || datos.temperatura_int_C === undefined) return null;

let id_disp = msg.payload.metadatos.id_dispositivo;
let temp = datos.temperatura_int_C;

let historicos = context.get('ventanas') || {};
if (!historicos[id_disp]) historicos[id_disp] = [];
let ventana = historicos[id_disp];

ventana.push(temp);
if (ventana.length > 20) ventana.shift();
historicos[id_disp] = ventana;
context.set('ventanas', historicos);

let alarma = false;
if (ventana.length >= 10) {
    let media = ventana.reduce((a, b) => a + b, 0) / ventana.length;
    let varianza = ventana.reduce((a, b) => a + Math.pow(b - media, 2), 0) / (ventana.length - 1);
    let desviacion = Math.sqrt(varianza) || 0.1;

    let z_score = Math.abs(temp - media) / desviacion;
    alarma = z_score > 2.5;
}

msg.prediccion_algoritmo = alarma;
msg.nombre_algoritmo = "Z-Score_Termico";
return msg;

let datos = msg.payload.datos_sensores;
if (!datos || datos.temperatura_int_C === undefined) return null;

let id_disp = msg.payload.metadatos.id_dispositivo;
let temp = datos.temperatura_int_C;
let alpha = 0.3;

let historico_ewma = context.get('valores_ewma') || {};
let ewma_previo = historico_ewma[id_disp];

if (ewma_previo === undefined) {
    historico_ewma[id_disp] = temp;
    context.set('valores_ewma', historico_ewma);
    msg.prediccion_algoritmo = false;
    msg.nombre_algoritmo = "EWMA_Termico";
    return msg;
}

let ewma_actual = (alpha * temp) + ((1 - alpha) * ewma_previo);
historico_ewma[id_disp] = ewma_actual;
context.set('valores_ewma', historico_ewma);

let error = Math.abs(temp - ewma_actual);
let alarma = error > 1.5;

msg.prediccion_algoritmo = alarma;
msg.nombre_algoritmo = "EWMA_Termico";
return msg;

let datos = msg.payload.datos_sensores;
if (!datos || datos.caudal_Lmin === undefined) return null;

let caudal = datos.caudal_Lmin;
let ts = msg.payload.timestamp_local;
let hora = new Date(ts * 1000).getUTCHours();

let mu_noche = 0.0;
if (hora >= 0 && hora <= 5) mu_noche = 1.0;
else if (hora > 5 && hora <= 7) mu_noche = 1.0 - ((hora - 5) / 2.0);
else if (hora >= 22 && hora <= 24) mu_noche = (hora - 22) / 2.0;

let umbral_base = 10.0;
let mu_alto = 0.0;
if (caudal > umbral_base * 2) mu_alto = 1.0;
else if (caudal > umbral_base) mu_alto = (caudal - umbral_base) / umbral_base;

let riesgo_fuga = Math.min(mu_noche, mu_alto);
let alarma = riesgo_fuga > 0.65;

msg.prediccion_algoritmo = alarma;
msg.nombre_algoritmo = "Logica_Difusa_Fugas";
return msg;

let real_es_anomalo = msg.payload.ground_truth.estado_anomalo;
let prediccion = msg.prediccion_algoritmo;
let timestamp = msg.payload.timestamp_local;
let algo = msg.nombre_algoritmo;

if (real_es_anomalo === undefined || prediccion === undefined) return null;

let stats = global.get('stats_' + algo) || { 
    TP: 0, FP: 0, TN: 0, FN: 0, 
    latencias: [], anomalia_activa: false, ts_inicio: 0 
};

if (real_es_anomalo && !stats.anomalia_activa) {
    stats.anomalia_activa = true;
    stats.ts_inicio = timestamp;
} else if (!real_es_anomalo) {
    stats.anomalia_activa = false;
    stats.ts_inicio = 0;
}

if (real_es_anomalo === true && prediccion === true) {
    stats.TP++;
    if (stats.ts_inicio > 0) {
        let latencia = timestamp - stats.ts_inicio;
        stats.latencias.push(latencia);
        stats.ts_inicio = 0;
    }
} 
else if (real_es_anomalo === false && prediccion === true) {
    stats.FP++;
} 
else if (real_es_anomalo === true && prediccion === false) {
    stats.FN++;
} 
else if (real_es_anomalo === false && prediccion === false) {
    stats.TN++;
}

global.set('stats_' + algo, stats);

let precision = (stats.TP + stats.FP) > 0 ? (stats.TP / (stats.TP + stats.FP)) : 0.0;
let recall = (stats.TP + stats.FN) > 0 ? (stats.TP / (stats.TP + stats.FN)) : 0.0;
let f1_score = (precision + recall) > 0 ? (2 * (precision * recall) / (precision + recall)) : 0.0;
let latencia_media = stats.latencias.length > 0 ? (stats.latencias.reduce((a,b)=>a+b,0) / stats.latencias.length) : 0.0;

msg.payload = {
    "Algoritmo": algo,
    "Metricas": {
        "Precision": (precision * 100).toFixed(2) + "%",
        "Recall_Sensibilidad": (recall * 100).toFixed(2) + "%",
        "F1_Score": f1_score.toFixed(4),
        "Latencia_Media": latencia_media.toFixed(1) + " seg"
    },
    "Matriz_Confusion": {
        "Verdaderos_Positivos_TP": stats.TP,
        "Falsos_Positivos_FP": stats.FP,
        "Verdaderos_Negativos_TN": stats.TN,
        "Falsos_Negativos_FN": stats.FN
    }
};

return msg;

// 1. Asegurar que leemos el objeto correctamente
let paquete = typeof msg.payload === "string" ? JSON.parse(msg.payload) : msg.payload;

// 2. Extraer los METADATOS (Las etiquetas o Tags para InfluxDB)
let meta = paquete.metadatos || {};

let etiquetas = {
    isla: meta.isla || "Desconocida",
    municipio: meta.municipio || "Desconocido",
    tipo_instalacion: meta.tipo_instalacion || "Desconocida",
    centro: meta.centro || "Desconocido",
    zona: meta.zona || "Desconocida",
    id_dispositivo: meta.id_dispositivo || "Unico",
    tipo_sensor: meta.tipo_sensor || "Desconocido"
};

// 3. Extraer los CAMPOS numéricos (Fields para InfluxDB) del nuevo bloque "datos_sensores"
let datos = paquete.datos_sensores || {};
let campos = {};

// Mapeamos los nombres nuevos a las columnas de tu base de datos
if (datos.temperatura_int_C !== undefined) campos.temperatura_interior = datos.temperatura_int_C;
if (datos.temperatura_ext_C !== undefined) campos.temperatura_exterior = datos.temperatura_ext_C;
if (datos.potencia_W !== undefined) campos.consumo_electrico_W = datos.potencia_W;
if (datos.caudal_Lmin !== undefined) campos.caudal_agua_Lmin = datos.caudal_Lmin;

// 4. Empaquetar y enviar a InfluxDB (Solo si encontró datos numéricos)
if (Object.keys(campos).length > 0) {
    msg.payload = [
        campos,     // Los valores numéricos puros (Fields)
        etiquetas   // Las etiquetas de categorización (Tags)
    ];
    return msg;
} else {
    // Si no detectó los datos, bloquea el flujo para no mandar basura a InfluxDB
    return null;
}

let p = msg.payload;

// Extraemos los valores clave para el TFM
let algoritmo = p.Algoritmo;
let precision = p.Metricas.Precision;
let f1 = p.Metricas.F1_Score;
let latencia = p.Metricas.Latencia_Media;
let tp = p.Matriz_Confusion.Verdaderos_Positivos_TP;
let fp = p.Matriz_Confusion.Falsos_Positivos_FP;
let fn = p.Matriz_Confusion.Falsos_Negativos_FN;

// Creamos una fila de texto separada por punto y coma
let linea_csv = `${algoritmo};${precision};${f1};${latencia};${tp};${fp};${fn}`;

msg.payload = linea_csv;
return msg;
